 53→	private getStrategy({
 54→		provider,
 55→	}: {
 56→		provider: 'github' | 'google';
 57→	}): GithubStrategy | GoogleStrategy {
 58→		if (provider === 'github') {
 59→			return this.githubStrategy;
 60→		}
 61→		return this.googleStrategy;
