 64→	async initiateOAuth({
 65→		provider,
 66→		invitationToken,
 67→	}: {
 68→		provider: 'github' | 'google';
 69→		invitationToken?: string;
 70→	}): Promise<URL> {
 71→		this.logger.log('Initiating OAuth', { provider });
 72→
 73→		const state = randomBytes(32).toString('hex');
 74→		const codeVerifier = generateCodeVerifier();
 75→
 76→		const stateData: IOAuthState = { codeVerifier, provider };
 77→		if (invitationToken !== undefined) {
 78→			stateData.invitationToken = invitationToken;
 79→		}
 80→
 81→		await this.redisWrite.set(
 82→			`oauth_state:${state}`,
 83→			JSON.stringify(stateData),
 84→			'EX',
 85→			OAUTH_STATE_TTL,
 86→		);
 87→
 88→		const strategy = this.getStrategy({ provider });
 89→		return strategy.createAuthorizationURL({ state, codeVerifier });
 90→	}
