 92→	async handleCallback({
 93→		provider,
 94→		code,
 95→		state,
 96→	}: {
 97→		provider: 'github' | 'google';
 98→		code: string;
 99→		state: string;
100→	}): Promise<
101→		| { type: 'auth_code'; code: string }
102→		| { type: 'linking_required'; linkingToken: string }
103→	> {
104→		this.logger.log('Handling OAuth callback', { provider });
105→
106→		const stateKey = `oauth_state:${state}`;
107→		const raw = await this.redisWrite.getdel(stateKey);
108→
109→		if (!raw) {
