121→		const profile = await strategy.getUserProfile({ accessToken });
122→
123→		const existingOAuthAccount =
124→			await this.oauthAccountService.findByProviderAndProviderId({
125→				provider: profile.provider,
126→				providerId: profile.provider_id,
127→			});
128→
129→		if (existingOAuthAccount) {
130→			await this.userService.updateLastLogin({ userId: existingOAuthAccount.user_id });
131→
132→			const authCode = randomBytes(32).toString('hex');
133→			const authCodeData: IAuthCode = {
