167→			);
168→
169→			return { type: 'linking_required', linkingToken };
170→		}
171→
172→		const newUser = await this.userService.create({
173→			data: {
174→				email: profile.email,
175→				name: profile.name,
176→				avatar_url: profile.avatar_url,
