184→				provider_id: profile.provider_id,
185→				email: profile.email || null,
186→				access_token: accessToken,
187→			},
188→		});
189→
190→		const authCode = randomBytes(32).toString('hex');
191→		const authCodeData: IAuthCode = {
192→			user_id: newUser._id,
193→			session_id: randomUUID(),
194→		};
