 1→import { Controller, Get, HttpStatus } from '@nestjs/common';
 2→import { ApiOkResponse, ApiOperation, ApiResponse, ApiTags } from '@nestjs/swagger';
 3→import {
 4→	HealthCheck,
 5→	HealthCheckResult,
 6→	HealthCheckService,
 7→	MemoryHealthIndicator,
 8→} from '@nestjs/terminus';
 9→
10→import { HealthService } from '@modules/health/health.service';
11→
12→let isSIGTERM = false;
13→process.on('SIGTERM', () => {
14→	isSIGTERM = true;
15→});
16→
17→@ApiTags('Health')
18→@Controller()
19→export class HealthController {
20→	constructor(
21→		private readonly health: HealthCheckService,
22→		private readonly memory: MemoryHealthIndicator,
23→		private readonly healthService: HealthService,
24→	) {}
25→
26→	@ApiOperation({ summary: 'Liveness probe' })
27→	@ApiOkResponse({
28→		description: 'Service is alive',
29→		schema: {
30→			type: 'object',
31→			properties: { status: { type: 'string', enum: ['up'] } },
32→		},
33→	})
34→	@Get('liveness')
35→	isItUp(): { status: 'up' } {
36→		return { status: 'up' };
37→	}
38→
39→	@ApiOperation({ summary: 'Readiness probe' })
40→	@ApiResponse({
41→		status: HttpStatus.OK,
42→		description: 'Service is ready to serve traffic',
43→	})
44→	@HealthCheck()
45→	@Get('readiness')
46→	async isItWorking(): Promise<HealthCheckResult> {
47→		if (isSIGTERM) {
48→			return { status: 'shutting_down', info: {}, error: {}, details: {} };
49→		}
50→
51→		return await this.health.check([
52→			() => this.healthService.isAppHealthy(),
53→			() => this.memory.checkHeap('memory_heap', 500 * 1024 * 1024),
54→		]);
55→	}
56→}
