import {
	Body,
	Controller,
	Get,
	HttpStatus,
	Post,
	Query,
	Req,
	Res,
	UnauthorizedException,
} from '@nestjs/common';
import { ApiOperation, ApiResponse, ApiTags } from '@nestjs/swagger';
import { FastifyReply, FastifyRequest } from 'fastify';

import { FRONTEND_URL } from '@constants/env-variables.constant';

import { AuthService } from '@modules/auth/auth.service';
import { REFRESH_TOKEN_COOKIE_NAME } from '@modules/auth/constants/auth.constant';
import { CurrentUser } from '@modules/auth/decorators/current-user.decorator';
import { Public } from '@modules/auth/decorators/public.decorator';
import { CreateCompanyDto } from '@modules/auth/dto/create-company.dto';
import { LinkAccountDto } from '@modules/auth/dto/link-account.dto';
import { TokenExchangeDto } from '@modules/auth/dto/token-exchange.dto';
import { IRequestUser } from '@modules/auth/types/auth.interface';

import { getEnv } from '@utils/get-env-variable.util';
import { isDevEnv } from '@utils/common.util';

@ApiTags('Auth')
@Controller('auth')
export class AuthController {
	constructor(private readonly authService: AuthService) {}

	@Public()
	@Get('github')
	@ApiOperation({ summary: 'Initiate GitHub OAuth' })
	@ApiResponse({ status: HttpStatus.FOUND, description: 'Redirect to GitHub' })
	async githubAuth(@Res() reply: FastifyReply): Promise<void> {
		const url = await this.authService.initiateOAuth({ provider: 'github' });
		reply.redirect(url.toString());
	}

	@Public()
	@Get('github/callback')
	@ApiOperation({ summary: 'Handle GitHub OAuth callback' })
	@ApiResponse({ status: HttpStatus.FOUND, description: 'Redirect to frontend' })
	async githubCallback(
		@Query('code') code: string,
		@Query('state') state: string,
		@Res() reply: FastifyReply,
	): Promise<void> {
		const result = await this.authService.handleCallback({
			provider: 'github',
			code,
			state,
		});
		const frontendUrl = getEnv<string>({ key: FRONTEND_URL });
		if (result.type === 'auth_code') {
			reply.redirect(`${frontendUrl}/auth/callback?code=${result.code}`);
		} else {
			reply.redirect(`${frontendUrl}/auth/link?linking_token=${result.linkingToken}`);
		}
	}

	@Public()
	@Get('google')
	@ApiOperation({ summary: 'Initiate Google OAuth' })
	@ApiResponse({ status: HttpStatus.FOUND, description: 'Redirect to Google' })
	async googleAuth(@Res() reply: FastifyReply): Promise<void> {
		const url = await this.authService.initiateOAuth({ provider: 'google' });
		reply.redirect(url.toString());
	}

	@Public()
	@Get('google/callback')
	@ApiOperation({ summary: 'Handle Google OAuth callback' })
	@ApiResponse({ status: HttpStatus.FOUND, description: 'Redirect to frontend' })
	async googleCallback(
		@Query('code') code: string,
		@Query('state') state: string,
		@Res() reply: FastifyReply,
	): Promise<void> {
		const result = await this.authService.handleCallback({
			provider: 'google',
			code,
			state,
		});
		const frontendUrl = getEnv<string>({ key: FRONTEND_URL });
		if (result.type === 'auth_code') {
			reply.redirect(`${frontendUrl}/auth/callback?code=${result.code}`);
		} else {
			reply.redirect(`${frontendUrl}/auth/link?linking_token=${result.linkingToken}`);
		}
	}

	@Public()
	@Post('token')
	@ApiOperation({ summary: 'Exchange auth code for JWT tokens' })
	@ApiResponse({ status: HttpStatus.OK, description: 'Returns access token, sets refresh cookie' })
	async exchangeToken(
		@Body() dto: TokenExchangeDto,
		@Req() request: FastifyRequest,
		@Res() reply: FastifyReply,
	): Promise<void> {
		const result = await this.authService.exchangeCode({
			code: dto.code,
			ip: request.ip,
			userAgent: request.headers['user-agent'] ?? '',
			provider: 'github',
		});

		reply.setCookie(REFRESH_TOKEN_COOKIE_NAME, result.refreshToken, {
			httpOnly: true,
			secure: !isDevEnv(),
			sameSite: 'strict',
			path: '/api/auth',
			maxAge: 30 * 24 * 60 * 60,
		});

		reply.send({ access_token: result.accessToken });
	}

	@Public()
	@Post('refresh')
	@ApiOperation({ summary: 'Refresh access token using refresh token cookie' })
	@ApiResponse({ status: HttpStatus.OK, description: 'Returns new access token, rotates refresh cookie' })
	@ApiResponse({ status: HttpStatus.UNAUTHORIZED, description: 'No or invalid refresh token' })
	async refresh(
		@Req() request: FastifyRequest,
		@Res() reply: FastifyReply,
	): Promise<void> {
		const refreshToken = (request.cookies as Record<string, string>)[
			REFRESH_TOKEN_COOKIE_NAME
		];
		if (!refreshToken) throw new UnauthorizedException('No refresh token');

		const result = await this.authService.refreshTokens({ refreshToken });

		reply.setCookie(REFRESH_TOKEN_COOKIE_NAME, result.refreshToken, {
			httpOnly: true,
			secure: !isDevEnv(),
			sameSite: 'strict',
			path: '/api/auth',
			maxAge: 30 * 24 * 60 * 60,
		});

		reply.send({ access_token: result.accessToken });
	}

	@Post('logout')
	@ApiOperation({ summary: 'Log out current session' })
	@ApiResponse({ status: HttpStatus.OK, description: 'Successfully logged out' })
	async logout(@CurrentUser() user: IRequestUser): Promise<{ success: boolean }> {
		await this.authService.logout({
			userId: user.user_id,
			sessionId: user.session_id,
		});
		return { success: true };
	}

	@Post('logout/all')
	@ApiOperation({ summary: 'Log out all sessions for current user' })
	@ApiResponse({ status: HttpStatus.OK, description: 'All sessions terminated' })
	async logoutAll(@CurrentUser() user: IRequestUser): Promise<{ success: boolean }> {
		await this.authService.logoutAll({ userId: user.user_id });
		return { success: true };
	}

	@Post('link')
	@ApiOperation({ summary: 'Link a new OAuth provider to current account' })
	@ApiResponse({ status: HttpStatus.OK, description: 'Account linked successfully' })
	async linkAccount(
		@Body() dto: LinkAccountDto,
		@CurrentUser() user: IRequestUser,
	): Promise<{ success: boolean }> {
		await this.authService.linkAccount({
			linkingToken: dto.linking_token,
			userId: user.user_id,
		});
		return { success: true };
	}

	@Post('signup/company')
	@ApiOperation({ summary: 'Create a company for the current user' })
	@ApiResponse({ status: HttpStatus.CREATED, description: 'Company created successfully' })
	async createCompany(
		@Body() dto: CreateCompanyDto,
		@CurrentUser() user: IRequestUser,
	): Promise<{ company_id: string }> {
		return this.authService.createCompany({
			name: dto.name,
			userId: user.user_id,
			sessionId: user.session_id,
		});
	}
}

import { UnauthorizedException } from '@nestjs/common';
import { Test, TestingModule } from '@nestjs/testing';

import { AuthController } from '@modules/auth/auth.controller';
import { AuthService } from '@modules/auth/auth.service';
import { REFRESH_TOKEN_COOKIE_NAME } from '@modules/auth/constants/auth.constant';
import { IRequestUser } from '@modules/auth/types/auth.interface';

jest.mock('@utils/get-env-variable.util', () => ({
	getEnv: jest.fn().mockReturnValue('http://localhost:3001'),
}));

jest.mock('@utils/common.util', () => ({
	isDevEnv: jest.fn().mockReturnValue(true),
}));

const mockAuthService = {
	initiateOAuth: jest.fn(),
	handleCallback: jest.fn(),
	exchangeCode: jest.fn(),
	refreshTokens: jest.fn(),
	logout: jest.fn(),
	logoutAll: jest.fn(),
	linkAccount: jest.fn(),
	createCompany: jest.fn(),
};

const mockReply = {
	redirect: jest.fn(),
	setCookie: jest.fn(),
	send: jest.fn(),
};

const mockRequest = {
	ip: '127.0.0.1',
	headers: { 'user-agent': 'TestAgent/1.0' },
	cookies: {},
};

const mockUser: IRequestUser = {
	user_id: 'user-123',
	session_id: 'session-456',
	role: 'admin',
	company_id: 'company-abc',
};

describe('AuthController', () => {
	let controller: AuthController;

	beforeEach(async () => {
		jest.clearAllMocks();

		mockReply.redirect.mockReturnValue(undefined);
		mockReply.setCookie.mockReturnValue(mockReply);
		mockReply.send.mockReturnValue(undefined);

		const module: TestingModule = await Test.createTestingModule({
			controllers: [AuthController],
			providers: [{ provide: AuthService, useValue: mockAuthService }],
		}).compile();

		controller = module.get<AuthController>(AuthController);
	});

	afterEach(() => jest.clearAllMocks());

	it('should be defined', () => {
		expect(controller).toBeDefined();
	});

	describe('githubAuth', () => {
		it('should call initiateOAuth with github and redirect to the returned URL', async () => {
			const url = new URL('https://github.com/login/oauth/authorize?state=abc');
			mockAuthService.initiateOAuth.mockResolvedValue(url);

			await controller.githubAuth(mockReply as never);

			expect(mockAuthService.initiateOAuth).toHaveBeenCalledWith({ provider: 'github' });
			expect(mockReply.redirect).toHaveBeenCalledWith(url.toString());
		});
	});

	describe('githubCallback', () => {
		it('should redirect to frontend /auth/callback when result is auth_code', async () => {
			mockAuthService.handleCallback.mockResolvedValue({
				type: 'auth_code',
				code: 'test-auth-code',
			});

			await controller.githubCallback('oauth-code', 'oauth-state', mockReply as never);

			expect(mockAuthService.handleCallback).toHaveBeenCalledWith({
				provider: 'github',
				code: 'oauth-code',
				state: 'oauth-state',
			});
			expect(mockReply.redirect).toHaveBeenCalledWith(
				'http://localhost:3001/auth/callback?code=test-auth-code',
			);
		});

		it('should redirect to frontend /auth/link when result is linking_required', async () => {
			mockAuthService.handleCallback.mockResolvedValue({
				type: 'linking_required',
				linkingToken: 'test-linking-token',
			});

			await controller.githubCallback('oauth-code', 'oauth-state', mockReply as never);

			expect(mockReply.redirect).toHaveBeenCalledWith(
				'http://localhost:3001/auth/link?linking_token=test-linking-token',
			);
		});
	});

	describe('googleAuth', () => {
		it('should call initiateOAuth with google and redirect to the returned URL', async () => {
			const url = new URL('https://accounts.google.com/o/oauth2/auth?state=xyz');
			mockAuthService.initiateOAuth.mockResolvedValue(url);

			await controller.googleAuth(mockReply as never);

			expect(mockAuthService.initiateOAuth).toHaveBeenCalledWith({ provider: 'google' });
			expect(mockReply.redirect).toHaveBeenCalledWith(url.toString());
		});
	});

	describe('googleCallback', () => {
		it('should redirect to frontend /auth/callback when result is auth_code', async () => {
			mockAuthService.handleCallback.mockResolvedValue({
				type: 'auth_code',
				code: 'google-auth-code',
			});

			await controller.googleCallback('google-code', 'google-state', mockReply as never);

			expect(mockAuthService.handleCallback).toHaveBeenCalledWith({
				provider: 'google',
				code: 'google-code',
				state: 'google-state',
			});
			expect(mockReply.redirect).toHaveBeenCalledWith(
				'http://localhost:3001/auth/callback?code=google-auth-code',
			);
		});

		it('should redirect to frontend /auth/link when result is linking_required', async () => {
			mockAuthService.handleCallback.mockResolvedValue({
				type: 'linking_required',
				linkingToken: 'google-linking-token',
			});

			await controller.googleCallback('google-code', 'google-state', mockReply as never);

			expect(mockReply.redirect).toHaveBeenCalledWith(
				'http://localhost:3001/auth/link?linking_token=google-linking-token',
			);
		});
	});

	describe('exchangeToken', () => {
		it('should exchange code, set refresh cookie, and send access token', async () => {
			mockAuthService.exchangeCode.mockResolvedValue({
				accessToken: 'access-jwt',
				refreshToken: 'refresh-uuid',
			});

			await controller.exchangeToken(
				{ code: 'valid-code' },
				mockRequest as never,
				mockReply as never,
			);

			expect(mockAuthService.exchangeCode).toHaveBeenCalledWith({
				code: 'valid-code',
				ip: '127.0.0.1',
				userAgent: 'TestAgent/1.0',
				provider: 'github',
			});
			expect(mockReply.setCookie).toHaveBeenCalledWith(
				REFRESH_TOKEN_COOKIE_NAME,
				'refresh-uuid',
				expect.objectContaining({
					httpOnly: true,
					sameSite: 'strict',
					path: '/api/auth',
					maxAge: 30 * 24 * 60 * 60,
				}),
			);
			expect(mockReply.send).toHaveBeenCalledWith({ access_token: 'access-jwt' });
		});

		it('should use empty string for user-agent when header is absent', async () => {
			mockAuthService.exchangeCode.mockResolvedValue({
				accessToken: 'access-jwt',
				refreshToken: 'refresh-uuid',
			});
			const requestNoAgent = { ip: '127.0.0.1', headers: {}, cookies: {} };

			await controller.exchangeToken(
				{ code: 'valid-code' },
				requestNoAgent as never,
				mockReply as never,
			);

			expect(mockAuthService.exchangeCode).toHaveBeenCalledWith(
				expect.objectContaining({ userAgent: '' }),
			);
		});
	});

	describe('refresh', () => {
		it('should read refresh cookie, rotate tokens, set new cookie, and send access token', async () => {
			mockAuthService.refreshTokens.mockResolvedValue({
				accessToken: 'new-access-jwt',
				refreshToken: 'new-refresh-uuid',
			});
			const requestWithCookie = {
				...mockRequest,
				cookies: { [REFRESH_TOKEN_COOKIE_NAME]: 'old-refresh-uuid' },
			};

			await controller.refresh(requestWithCookie as never, mockReply as never);

			expect(mockAuthService.refreshTokens).toHaveBeenCalledWith({
				refreshToken: 'old-refresh-uuid',
			});
			expect(mockReply.setCookie).toHaveBeenCalledWith(
				REFRESH_TOKEN_COOKIE_NAME,
				'new-refresh-uuid',
				expect.objectContaining({
					httpOnly: true,
					sameSite: 'strict',
					path: '/api/auth',
					maxAge: 30 * 24 * 60 * 60,
				}),
			);
			expect(mockReply.send).toHaveBeenCalledWith({ access_token: 'new-access-jwt' });
		});

		it('should throw UnauthorizedException when refresh cookie is absent', async () => {
			const requestNoCookie = { ...mockRequest, cookies: {} };

			await expect(
				controller.refresh(requestNoCookie as never, mockReply as never),
			).rejects.toThrow(UnauthorizedException);

			expect(mockAuthService.refreshTokens).not.toHaveBeenCalled();
		});
	});

	describe('logout', () => {
		it('should call authService.logout with userId and sessionId from current user', async () => {
			mockAuthService.logout.mockResolvedValue(undefined);

			const result = await controller.logout(mockUser);

			expect(mockAuthService.logout).toHaveBeenCalledWith({
				userId: 'user-123',
				sessionId: 'session-456',
			});
			expect(result).toEqual({ success: true });
		});
	});

	describe('logoutAll', () => {
		it('should call authService.logoutAll with userId from current user', async () => {
			mockAuthService.logoutAll.mockResolvedValue(undefined);

			const result = await controller.logoutAll(mockUser);

			expect(mockAuthService.logoutAll).toHaveBeenCalledWith({ userId: 'user-123' });
			expect(result).toEqual({ success: true });
		});
	});

	describe('linkAccount', () => {
		it('should call authService.linkAccount with linking token and userId', async () => {
			mockAuthService.linkAccount.mockResolvedValue(undefined);

			const result = await controller.linkAccount(
				{ linking_token: 'link-tok' },
				mockUser,
			);

			expect(mockAuthService.linkAccount).toHaveBeenCalledWith({
				linkingToken: 'link-tok',
				userId: 'user-123',
			});
			expect(result).toEqual({ success: true });
		});
	});

	describe('createCompany', () => {
		it('should call authService.createCompany and return company_id', async () => {
			mockAuthService.createCompany.mockResolvedValue({ company_id: 'new-company-id' });

			const result = await controller.createCompany({ name: 'Acme Corp' }, mockUser);

			expect(mockAuthService.createCompany).toHaveBeenCalledWith({
				name: 'Acme Corp',
				userId: 'user-123',
				sessionId: 'session-456',
			});
			expect(result).toEqual({ company_id: 'new-company-id' });
		});
	});
});

